import React from "react"
import { properties } from '../../properties/properties.js'
import {Tab, Tabs, TabList, TabPanel} from 'react-tabs'
import 'react-tabs/style/react-tabs.css'
import Box from '@mui/material/Box';
import SaveIcon from '@mui/icons-material/Save';
import CancelIcon from '@mui/icons-material/Close';
import EditIcon from '@mui/icons-material/Edit';
import {
    GridRowModes,
    DataGrid,
    GridActionsCellItem,
    GridRowId
  } from '@mui/x-data-grid';


class CyberAdmin extends React.Component {

    constructor(props) {
        super(props);
        this.state = { screen: 1, settingsResult: []
        };
    }



    handleSaveClick = (id) => {

      };


      handleCancelClick = (id) => {

      }

      handleEditClick = (id) => {

      }


    componentDidMount() {

        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var backUrl = properties.backend + `cyberraptor/getSettings`

        fetch(backUrl, {
          "method": "GET",
          headers: headers
        })
        .then(response => response.json())
        .then(response => {
            this.setState({settingsResult: response})
            this.setState({screen: 1})
        })
        .catch(err => {
          console.log(err);
        });

    }


    render() {


        var header = "Loading ..."
        var content = []

        if (this.state.screen == 1) {
            var tabContent = []

            header = ""


            var teamsResult = []


            var columns = [{headerName: 'ID', field: 'id', width: 100},{headerName: 'Team Name', field: 'team_name', width: 150},
            {headerName: 'Cap', field: 'cap', width: 100, editable: true}

        ]


/*
            for(var index in this.state.settingsResult.teams) {
                var team = this.state.settingsResult.teams[index]
                console.log(team)


            }
*/

            if (this.state.settingsResult.teams) {
            teamsResult.push(    <Box sx={{ height: 400, width: 400 }}>
            <DataGrid
              rows={this.state.settingsResult.teams}
              columns={columns}
              editMode="row"
              initialState={{
                pagination: {
                  paginationModel: {
                    pageSize: 50,
                  },
                },
              }}
              pageSizeOptions={[50]}
              disableRowSelectionOnClick
            />
          </Box>)
            }

            tabContent.push(<Tabs>
                    <TabList>
                        <Tab>Team Cap</Tab>
                        <Tab>Algorithms</Tab>
                    </TabList>
                    <TabPanel>
                        <h3>Team Cap</h3>
                        {teamsResult}
                    </TabPanel>
                    <TabPanel>
                        <h3>Algorithm</h3>
                    </TabPanel>
                </Tabs>)

            content.push(tabContent)
        }


        return (
            <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}
            </div>
        );


      }


}


export default CyberAdmin
